83	- (void)initSubviews {
84	    if ([CTMediator isMona]) {
85	        [self goToStep3];
86	        return;
87	    }
88	    [self.view addSubview:self.step1View];
89	    [self.step1View mas_makeConstraints:^(MASConstraintMaker *make) {
90	        make.edges.equalTo(self.view);
91	    }];
92	    @weakify(self)
93	    [[self.step1View.lockButton rac_signalForControlEvents:UIControlEventTouchUpInside] subscribeNext:^(__kindof UIControl * _Nullable x) {
94	        @strongify(self)
95	        if(CTMediator.carState.extState.vehicleMode == XPCarExtVehicleModeShow){
96	            [QMUIAlertController showAlertWithTitle:@"展车模式中，请确认车内乘客离开后再锁车" message:nil leftButtionTitle:@"取消" leftButtonType:QMUIAlertActionStyleCancel leftAction:^(__kindof QMUIAlertController * _Nonnull alertVC, QMUIAlertAction * _Nonnull action) {
97	                
98	            } rightButtonTitle:@"立即锁车" rightButtonType:QMUIAlertActionStyleDefault rightAction:^(__kindof QMUIAlertController * _Nonnull alertVC, QMUIAlertAction * _Nonnull action) {
99	                @strongify(self)
100	                [self handleLockButton];
101	            }];
102	            return;
103	        }
104	        [self handleLockButton];
105	    }];
106	
107	    [[self.step1View.backButton rac_signalForControlEvents:UIControlEventTouchUpInside] subscribeNext:^(__kindof UIControl * _Nullable x) {
108	        @strongify(self)
109	        [self.navigationController popViewControllerAnimated:YES];
110	    }];
111	}
