113	- (void)handleLockButton{
114	    if([self judgeCanLock]) {
115	        self.step1View.lockButton.enabled = NO;
116	        [XPToast showLoadingMessage:@"锁车中..." hasMask:YES];
117	        [self lockButtonTouch];
118	    }
119	}
120	
121	- (void)lockButtonTouch{
122	    if ([CTMediator isSDK2ndCar]){
123	        [self lockButtonTouch2nd];
124	        return;
125	    }
126	    [[self.carStateBusinessOperator.controlDoorCommand execute:@{@"isLock":@(YES),
127	                                                                 @"timeout":@(MQTTCallbackDefaultTimeout)
128	    }].deliverOnMainThread subscribeError:^(NSError * _Nullable error) {
129	        self.step1View.lockButton.enabled = YES;
130	        [XPToast dismissLoadingMessage];
131	        [XPToast removePreviewToastOnView];
132	        [self showFailToLockAlertWithError:error];
133	        DLogTagInfo(kBLEKeyTag, @"锁车失败:%@", error.userInfo[NSLocalizedFailureReasonErrorKey]);
134	    } completed:^{
135	        self.step1View.lockButton.enabled = YES;
136	        DLogTagInfo(kBLEKeyTag, @"锁车成功，刷新整车状态，并跳转到删除授权第二步");
137	        [CarControlManager.instance sendForceUploadCarStateInfoRequestMessageIfNeedWithStyle:CarControlStyleReal successBlock:^(id data) {
138	            xp_async_execute_in_main_thread(^{
139	                [XPToast dismissLoadingMessage];
140	                [self.step1View removeFromSuperview];
141	                [self goToStep2];
142	            });
143	            
144	        } failBlock:^(NSString *message, id data) {
145	            xp_async_execute_in_main_thread(^{
146	                [XPToast dismissLoadingMessage];
147	                [self.step1View removeFromSuperview];
148	                [self goToStep2];
149	            });
150	        } timeoutBlock:^{
151	            xp_async_execute_in_main_thread(^{
152	                [XPToast dismissLoadingMessage];
153	                [self.step1View removeFromSuperview];
154	                [self goToStep2];
155	            });
156	        }];
157	    }];
158	}
159	
160	- (void)lockButtonTouch2nd{
161	    [[XPVehicleSDK.shared.vehicleManager currentVehicle]
162	     sendCommand:XPVehicleCommandLock success:^{
163	        self.step1View.lockButton.enabled = YES;
164	        DLogTagInfo(kBLEKeyTag, @"锁车成功，刷新整车状态，并跳转到删除授权第二步");
165	        if ([CTMediator isSDK2ndCar]) {
166	            [[XPVehicleSDK.shared.vehicleManager currentVehicle]
167	                       sendCommand:XPVehicleCommandForceUploadCarInfo extParams:nil success:^{
168	                    [XPToast dismissLoadingMessage];
169	                    [self.step1View removeFromSuperview];
170	                    [self goToStep2];
171	            } failed:^(XPVehicleError * _Nonnull error) {
172	                [XPToast dismissLoadingMessage];
173	                [self.step1View removeFromSuperview];
174	                [self goToStep2];
175	            }];
176	        } else {
177	            [CarControlManager.instance sendForceUploadCarStateInfoRequestMessageIfNeedWithStyle:CarControlStyleReal successBlock:^(id data) {
178	                xp_async_execute_in_main_thread(^{
179	                    [XPToast dismissLoadingMessage];
180	                    [self.step1View removeFromSuperview];
181	                    [self goToStep2];
182	                });
183	                
184	            } failBlock:^(NSString *message, id data) {
185	                xp_async_execute_in_main_thread(^{
186	                    [XPToast dismissLoadingMessage];
187	                    [self.step1View removeFromSuperview];
188	                    [self goToStep2];
189	                });
190	            } timeoutBlock:^{
191	                xp_async_execute_in_main_thread(^{
192	                    [XPToast dismissLoadingMessage];
193	                    [self.step1View removeFromSuperview];
194	                    [self goToStep2];
195	                });
196	            }];
197	        }
198	    } failed:^(XPVehicleError * error) {
199	        self.step1View.lockButton.enabled = YES;
200	        [XPToast dismissLoadingMessage];
201	        [XPToast removePreviewToastOnView];
202	        dispatch_async(dispatch_get_main_queue(), ^{
203	            NSString *title = @"锁车失败，请检查";
204	            NSString *message = @"1. 请确保主驾无人\n2. 车门及前后盖已关闭\n3. 挡位置于P挡\n4. 车辆网络良好";
205	            if(error.channel == XPVehicleChannelTCP && error.code == 12){
206	                title = error.msg;
207	                message = nil;
208	            }
209	            [QMUIAlertController showAlertWithTitle:title
210	                                            message:message
211	                                   leftButtionTitle:nil
212	                                     leftButtonType:QMUIAlertActionStyleCancel
213	                                         leftAction:nil
214	                                   rightButtonTitle:@"确认"
215	                                    rightButtonType:QMUIAlertActionStyleDefault
216	                                        rightAction:nil];
217	        });
218	        DLogTagInfo(kBLEKeyTag, @"锁车失败:%@", error.msg);
219	    }];
220	}
