231	- (void)goToStep2 {
232	    [self.view addSubview:self.step2View];
233	    [self.step2View mas_makeConstraints:^(MASConstraintMaker *make) {
234	        make.edges.equalTo(self.view);
235	    }];
236	    
237	    __weak typeof(self) weakSelf = self;
238	    self.deleteTimer = [NSTimer bk_scheduledTimerWithTimeInterval:3 block:^(NSTimer *timer) {
239	        [[weakSelf.checkCarStatusViewModel.checkVehicleStatusCommand execute:@{@"vin":weakSelf.vin?:@"",
240	                                                             @"operType":@(XPKeyCardOperationTypeDelete),
241	                                                             @"cardType":@(XPBLEKeyCardType_BLEKey),
242	                                                             @"remoteLockResult":@(CTMediator.carState.doorInfo.driver_door_lock_st? 1:2)
243	        }] subscribeNext:^(id  _Nullable x) {
244	            
245	        } error:^(NSError * _Nullable error) {
246	            DLogTagInfo(kBLEKeyTag, @"检车车况失败%@", error);
247	        } completed:^{
248	            if(CTMediator.carState.powerInfo.car_igon_state != 0) {
249	                DLogTagInfo(kBLEKeyTag, @"检车车况正常，但车辆处于上电状态，跳转到失败界面");
250	                [weakSelf.deleteTimer invalidate];
251	                weakSelf.deleteTimer = nil;
252	                [weakSelf.step2View removeFromSuperview];
253	
254	                [weakSelf goToFailPageWithTips:@"车辆已上电，请确认锁车下电后重试"];
255	            } else {
256	                DLogTagInfo(kBLEKeyTag, @"检车车况正常，跳转到解除车辆授权第三步");
257	                [weakSelf.deleteTimer invalidate];
258	                weakSelf.deleteTimer = nil;
259	                [weakSelf.step2View removeFromSuperview];
260	                
261	                [weakSelf goToStep3];
262	            }
263	        }];
264	    } repeats:YES];
265	}
