267	- (void)goToStep3 {
268	    [self.view addSubview:self.step3View];
269	    [self.step3View mas_makeConstraints:^(MASConstraintMaker *make) {
270	        make.edges.equalTo(self.view);
271	    }];
272	    self.step3View.titleLabel.text = @"正在解除车辆授权";
273	    self.step3View.bleImageView.image = [UIImage imageNamed:@"ic_releaseauth"];
274	    [self.step3View.animationView stop];
275	    [self.step3View.animationView setCompatibleAnimation:[[CompatibleAnimation alloc] initWithName:@"createBleKeyStep2" subdirectory:nil bundle:NSBundle.mainBundle]];
276	    self.step3View.animationView.loopAnimationCount = -1;
277	    [self.step3View.animationView play];
278	    
279	    [self checkIsDeleteSuccessAfterDoorIsLocked];
280	    [self deleteWarranty];
281	}
