283	- (void)deleteWarranty {
284	    if (self.isAuthorizedPerson) {
285	        @weakify(self);
286	        [[CTMediator deleteGrantedVehicleWithVin:self.vin] subscribeNext:^(id  _Nullable x) {
287	        } error:^(NSError * _Nullable error) {
288	            DLogTagInfo(kBLEKeyTag, @"删除授权失败:%@", error);
289	        } completed:^{
290	            @strongify(self);
291	            [XPToast showMessage:@"已解绑车辆"];
292	            [self refreshAuthList];
293	            if ([CTMediator isSDK2ndCar]) {
294	                [XPVehicleSDKDealTool clearCacheWhenAuthorizationCanceledWithVin:self.vin];
295	            } else {
296	                //强制删除本地钥匙
297	                //安全钥匙
298	                BOOL isDeletedCard = [self.card deleteCard];
299	                DLogTagInfo(kBLEKeyTag, @"删除本地安全钥匙%@",isDeletedCard?@"成功":@"失败");
300	                
301	                //证书or自研钥匙
302	                BOOL isDeletedCertKeyCard = [XPBLEKeyManager.instance deleteCertKeyWithVin:self.vin];
303	                DLogTagInfo(kBLEKeyTag, @"删除本地证书钥匙%@",isDeletedCertKeyCard?@"成功":@"失败");
304	            }
305	            
306	            [self refreshCarInfosAndUserInfo];
307	            //跳至车控页
308	            [CTMediator.tabBarController switchToTab:XPTabBarIndexCar];
309	            //退出到主页
310	            [CTMediator.currentTabBarNavigation popToRootViewControllerAnimated:YES];
311	        }];
312	    } else {
313	        @weakify(self);
314	        [[self.cancelWarrantyViewModel.requestCancelDriverCommand execute:nil] subscribeNext:^(id  _Nullable x) {
315	        } error:^(NSError * _Nullable error) {
316	            DLogTagInfo(kBLEKeyTag, @"删除授权失败:%@", error);
317	        } completed:^{
318	            @strongify(self);
319	            [XPToast showMessage:@"已解除授权"];
320	            DLogTagInfo(kBLEKeyTag, @"解除授权成功");
321	            [self refreshAuthList];
322	            for (UIViewController *vc in self.navigationController.viewControllers) {
323	                if([vc isKindOfClass:XPNewCarPermissionListViewController.class]) {
324	                    [self.navigationController popToViewController:vc animated:YES];
325	                    break;
326	                }
327	            }
328	        }];
329	    }
330	}
