332	- (void)refreshCarInfosAndUserInfo {
333	    @weakify(self)
334	    if ([CTMediator isSDK2ndCar]) {
335	        [XPVehicleSDK.shared.vehicleManager requestVehicleInfo: ^{
336	            @strongify(self)
337	            DLogTagInfo(kBLEKeyTag, @"车辆授权，刷新车辆数据成功");
338	            [[CTMediator refresh] subscribeCompleted:^{
339	                DLogTagInfo(kBLEKeyTag, @"车辆授权，刷新个人信息成功");
340	            }];
341	            [NSNotificationCenter.defaultCenter postNotificationName:XPCarPermissionNotificaiton object:nil];
342	        } failed :^(XPVehicleError * error) {
343	            DLogTagInfo(kBLEKeyTag, @"车辆授权，刷新车辆数据失败");
344	        }];
345	        return;
346	    }
347	    //刷新车辆数据
348	    [[CTMediator refreshMyCarInfos] subscribeError:^(NSError * _Nullable error) {
349	        DLogTagInfo(kBLEKeyTag, @"车辆授权，刷新车辆数据失败");
350	    } completed:^{
351	        DLogTagInfo(kBLEKeyTag, @"车辆授权，刷新车辆数据成功");
352	        [[CTMediator refresh] subscribeCompleted:^{
353	            DLogTagInfo(kBLEKeyTag, @"车辆授权，刷新个人信息成功");
354	        }];
355	        [NSNotificationCenter.defaultCenter postNotificationName:XPCarPermissionNotificaiton object:nil];
356	    }];
357	}
