359	- (void)refreshAuthList {
360	    DLogTagInfo(kBLEKeyTag, @"删除授权后立刻刷新授权列表");
361	    XPDigitalKeyManageViewModel *viewModel = [XPBLEKeyManager.instance viewModelWithVin:self.vin];
362	    [viewModel refeshListAndDrivers];
363	    
364	}
