366	- (void)checkIsDeleteSuccessAfterDoorIsLocked {
367	    self.step2View.secondsLabel.text = [NSString stringWithFormat:@"%ld", (long)self.seconds];
368	    self.step2View.sLabel.text = @"s";
369	    self.step3View.secondsLabel.text = [NSString stringWithFormat:@"%ld", (long)self.seconds];
370	    self.step3View.sLabel.text = @"s";
371	    __weak typeof(self) weakSelf = self;
372	    self.secondsTimer = [NSTimer bk_scheduledTimerWithTimeInterval:1 block:^(NSTimer *timer) {
373	        weakSelf.seconds--;
374	        weakSelf.step2View.secondsLabel.text = [NSString stringWithFormat:@"%ld", (long)weakSelf.seconds];
375	        weakSelf.step3View.secondsLabel.text = [NSString stringWithFormat:@"%ld", (long)weakSelf.seconds];
376	        if(weakSelf.seconds <= 0) {
377	            [weakSelf.secondsTimer invalidate];
378	            weakSelf.secondsTimer = nil;
379	            if(!weakSelf.isDeleteSuccess) {
380	                DLogTagInfo(kBLEKeyTag, @"解除授权%ld秒已到，未成功，跳转到失败页面", (long)kDeleteDuration);
381	                [weakSelf goToFailPageWithTips:@"抱歉发生了错误，请稍后重试"];
382	            }
383	        }
384	    } repeats:YES];
385	}
