387	- (void)goToFailPageWithTips:(NSString *)tips {
388	    for (UIView *subview in self.view.subviews) {
389	        [subview removeFromSuperview];
390	    }
391	    
392	    [self.view addSubview:self.errorView];
393	    [self.errorView mas_makeConstraints:^(MASConstraintMaker *make) {
394	        make.edges.equalTo(self.view);
395	    }];
396	    self.errorView.titleLabel.text = @"解除授权失败";
397	    self.errorView.descLabel.text = tips;
398	    @weakify(self);
399	    [[self.errorView.closeButton rac_signalForControlEvents:UIControlEventTouchUpInside] subscribeNext:^(__kindof UIControl * _Nullable x) {
400	        @strongify(self);
401	        [self.navigationController popViewControllerAnimated:YES];
402	    }];
403	}
