405	- (void)showFailToLockAlertWithError:(NSError *)error{
406	    //主线程处理UI
407	    dispatch_async(dispatch_get_main_queue(), ^{
408	        NSString *title = @"锁车失败，请检查";
409	        NSString *message = @"1. 请确保主驾无人\n2. 车门及前后盖已关闭\n3. 挡位置于P挡\n4. 车辆网络良好";
410	        if([error.userInfo[@"code"] integerValue] == MQTTResponseCodeSomeoneIsControlingCar){
411	            title = error.userInfo[NSLocalizedFailureReasonErrorKey];
412	            message = nil;
413	        }
414	        [QMUIAlertController showAlertWithTitle:title
415	                                        message:message
416	                               leftButtionTitle:nil
417	                                 leftButtonType:QMUIAlertActionStyleCancel
418	                                     leftAction:nil
419	                               rightButtonTitle:@"确认"
420	                                rightButtonType:QMUIAlertActionStyleDefault
421	                                    rightAction:nil];
422	    });
423	}
