197	- (void)jumpToHuamiApp {
198	    NSString* url = @"amazfit://nfccard/create_car_card?";
199	    NSDictionary* params = @{@"vin":CTMediator.vin,
200	                               @"opType":@(1),
201	                               @"effectiveTime":@((uint64_t)ceil(time(NULL)/60.0)),
202	                               @"validTime":@(0)};
203	    @weakify(self);
204	    if(self.isNeedCreateBigCard) {
205	        [[[XPBLEKeyManager.instance.generateTokenCommand execute:nil] zipWith:[XPBLEKeyManager.instance.generateTokenForHuamiCommand execute:params]]
206	           subscribeNext:^(RACTwoTuple* _Nullable datas) {
207	            @strongify(self);
208	            DLogTagInfo(kBLEKeyTag, @"datas = %@",datas);
209	            RACTupleUnpack(NSDictionary* bigDcitionary,NSDictionary* smallDictionary) = datas;
210	            if(bigDcitionary[@"token"]) {
211	                NSString* parms = [NSString stringWithFormat:@"token=%@&keyToken=%@&action=bigCard",bigDcitionary[@"token"],smallDictionary[@"token"]];
212	                NSString* URL = [url stringByAppendingString:parms];
213	                DLogTagInfo(kBLEKeyTag, @"正在打开华米手表APP,url=%@",URL);
214	                [XPRouterUtil openURL:URL];
215	            }
216	          } error:^(NSError * _Nullable error) {
217	              @strongify(self);
218	              DLogTagError(kBLEKeyTag, @"error:%@",error);
219	              if(error.code == 11092112) {
220	                  [self dealWithWhenKeyIsExistedThenCreate:YES];
221	              }
222	          }];
223	    } else {
224	        [[XPBLEKeyManager.instance.generateTokenForHuamiCommand execute:@{@"uid":@(CTMediator.uid),@"vin":CTMediator.vin}] subscribeNext:^(NSDictionary* _Nullable smallDictionary) {
225	            @strongify(self);
226	            DLogTagInfo(kBLEKeyTag, @"data = %@",smallDictionary);
227	            if(smallDictionary[@"token"]) {
228	                 NSMutableDictionary* keyTokens = [NSMutableDictionary dictionary];
229	                 [keyTokens setObject:smallDictionary[@"token"] forKey:@"keyToken"];
230	                 [keyTokens setObject:@"" forKey:@"token"];
231	                 [keyTokens setObject:@"keyCard" forKey:@"action"];
232	                 NSMutableArray* params = [NSMutableArray arrayWithCapacity:2];
233	                 for (NSString* key in keyTokens.allKeys) {
234	                     [params addObject:[NSString stringWithFormat:@"%@=%@",key,[keyTokens objectForKey:key]]];
235	                 }
236	                NSString* URL = [url stringByAppendingString:[params componentsJoinedByString:@"&"]];
237	                DLogTagInfo(kBLEKeyTag, @"正在打开华米手表APP,url=%@",URL);
238	                [XPRouterUtil openURL:URL];
239	            } else {
240	                DLogTagInfo(kBLEKeyTag, @"token为空");
241	            }
242	        } error:^(NSError * _Nullable error) {
243	            DLogTagError(kBLEKeyTag, @"error:%@",error);
244	            @strongify(self);
245	            if(error.code == 11092112) {
246	                [self dealWithWhenKeyIsExistedThenCreate:YES];
247	            }
248	        } completed:^{
249	        }];
250	    }
251	}
