253	- (void)dealWithWhenKeyIsExistedThenCreate:(BOOL)create {
254	    DLogTagInfo(kBLEKeyTag, @"服务端已存在手表钥匙，需要删除");
255	    BOOL isSelfKey = NO;
256	    NSString *cardNo = nil;
257	    if ([CTMediator isSDK2ndCar]) {
258	        XPBLEKeyCard *watchCard = [XPBLEKeyCard yy_modelWithDictionary:[[XPVehicleSDK.shared.vehicleManager.currentVehicle.digitalKeyManager digitalKeyWithKeyCardType:XPKeyCardTypeNFC_WATCH].bleKeyCard toDict]];
259	        cardNo = watchCard.cardNo;
260	        isSelfKey = watchCard != nil && (watchCard.status == XPBLEKeyCardStatusActivated || watchCard.status == XPBLEKeyCardStatusToBeActivated);
261	    } else {
262	        XPDigitalKeyManageViewModel *viewModel = [XPBLEKeyManager.instance viewModelWithVin:self.vin];
263	        isSelfKey = [viewModel myWatchNFCCardIsExisted] && ([viewModel myWatchCard].status == XPBLEKeyCardStatusActivated || [viewModel myWatchCard].status == XPBLEKeyCardStatusToBeActivated);
264	        cardNo = [viewModel myWatchCard].cardNo;
265	    }
266	    if(isSelfKey) {
267	        DLogTagInfo(kBLEKeyTag, @"服务端已存在手表钥匙，而且钥匙是自己的(激活中或者待激活)，则先删除自己的");
268	        [self deleteKeyWithCardNumber:cardNo thenCreate:create];
269	    } else {
270	        DLogTagInfo(kBLEKeyTag, @"服务端已存在手表钥匙，而且钥匙是别人的，不能删除，直接跳到失败页面");
271	        [self goToFailViewWithTips:@"请重新再试"];
272	    }
273	}
