275	- (void)deleteKeyWithCardNumber:(NSString *)cardNumnber thenCreate:(BOOL)create {
276	    @weakify(self);
277	    [[[XPBLEKeyManager.instance.destoryBLEKeyCommand execute:cardNumnber] takeUntil:self.rac_willDeallocSignal].deliverOnMainThread subscribeError:^(NSError * _Nullable error) {
278	        @strongify(self)
279	        DLogTagError(kBLEKeyTag, @"%@",error);
280	
281	        if (ERR_IFAA_DEVICE_NOT_REGISTERED == error.code) {
282	            [[[XPBLEKeyManager.instance.requestDestroyCardInThisDeviceCommand execute:nil] takeUntil:self.rac_willDeallocSignal].deliverOnMainThread subscribeError:^(NSError * _Nullable error) {
283	                DLogTagInfo(kBLEKeyTag, @"注销失败%@", error);
284	            } completed:^{
285	                DLogTagInfo(kBLEKeyTag, @"申请注销成功");
286	                @strongify(self)
287	                [self refreshKeyList];
288	                if(create) {
289	                    DLogTagInfo(kBLEKeyTag, @"检查钥匙的删除状态");
290	                    [self checkCardIsDeletedAndCreate];
291	                }
292	            }];
293	        } else {
294	            DLogTagInfo(kBLEKeyTag, @"注销失败%@", error.localizedFailureReason);
295	        }
296	    } completed:^{
297	        DLogTagInfo(kBLEKeyTag, @"申请注销成功");
298	        @strongify(self)
299	        if(create) {
300	            DLogTagInfo(kBLEKeyTag, @"检查钥匙的删除状态");
301	            [self checkCardIsDeletedAndCreate];
302	        }
303	    }];
304	}
