298	- (void)deleteCardThenCheck:(XPBLEKeyCard*)card {
299	    __CHECK(XPBLEKeyCardStatusInvalid != card.status)
300	    @weakify(self)
301	    if (![card.deviceId isEqualToString:UIDevice.devideId]) {
302	        [[[XPBLEKeyManager.instance.requestCancelShareCardCommand execute:@[card.cardNo]] takeUntil:self.rac_willDeallocSignal].deliverOnMainThread subscribeError:^(NSError * _Nullable error) {
303	            DLogTagInfo(kBLEKeyTag, @"删除蓝牙钥匙失败:%@",error.localizedFailureReason);
304	        } completed:^{
305	            DLogTagInfo(kBLEKeyTag, @"申请删除成功");
306	            @strongify(self)
307	            [card markAsRemoving];
308	            [[XPBLEKeyManager.instance viewModelWithVin:self.vin] refeshList];
309	            [self checkCardIsExisted];
310	        }];
311	    } else {
312	        [[[XPBLEKeyManager.instance.destoryBLEKeyCommand execute:card.cardNo] takeUntil:self.rac_willDeallocSignal].deliverOnMainThread subscribeError:^(NSError * _Nullable error) {
313	            @strongify(self)
314	            DLogTagError(kBLEKeyTag, @"%@",error);
315	            
316	            [[[XPBLEKeyManager.instance.requestDestroyCardInThisDeviceCommand execute:nil] takeUntil:self.rac_willDeallocSignal].deliverOnMainThread subscribeError:^(NSError * _Nullable error) {
317	                DLogTagInfo(kBLEKeyTag, @"注销失败%@", error);
318	            } completed:^{
319	                DLogTagInfo(kBLEKeyTag, @"申请注销成功");
320	                @strongify(self)
321	                [card markAsRemoving];
322	                [[XPBLEKeyManager.instance viewModelWithVin:self.vin] refeshList];
323	                [self checkCardIsExisted];
324	            }];
325	            
326	        } completed:^{
327	            DLogTagInfo(kBLEKeyTag, @"申请注销成功");
328	            @strongify(self)
329	            [card markAsRemoving];
330	            [self checkCardIsExisted];
331	        }];
332	    }
333	}
334	
335	- (void)checkCardIsExisted {
336	    //5秒刷新一次
337	    __weak typeof(self) weakSelf = self;
338	    XPDigitalKeyManageViewModel* viewModel = [XPBLEKeyManager.instance viewModelWithVin:self.vin];
339	    self.deleteTimer = [NSTimer bk_scheduledTimerWithTimeInterval:5 block:^(NSTimer *timer) {
340	        if ([CTMediator isSDK2ndCar]) {
341	            [XPVehicleSDK.shared.vehicleManager.currentVehicle.digitalKeyManager refreshRemoteKeyList];
342	        } else {
343	            [viewModel refeshList];
344	        }
345	        BOOL isDeleted = NO;
346	        if(weakSelf.card.cardType == XPBLEKeyCardType_NFCWatchKey) {
347	            isDeleted = [CTMediator isSDK2ndCar]?(![XPVehicleSDK.shared.vehicleManager.currentVehicle.digitalKeyManager digitalKeyWithKeyCardType:XPKeyCardTypeNFC_WATCH]):(![viewModel myWatchNFCCardIsActived]);
348	        } else if(weakSelf.card.cardType == XPBLEKeyCardType_BLEKey) {
349	            isDeleted = !([CTMediator isSDK2ndCar]?[XPVehicleSDK.shared.vehicleManager.currentVehicle.digitalKeyManager existValidBlePrivateKey]:[viewModel myBleCardIsExisted]);
350	        }
351	        if(isDeleted && weakSelf.card.cardType == XPBLEKeyCardType_BLEKey && viewModel.certKeyCard) {
352	            DLogTagInfo(kBLEKeyTag, @"安全钥匙已删除，开始删除证书钥匙");
353	            [weakSelf deleteCertKeyWithCertKeyCardNo:viewModel.certKeyCard.cardNo];
354	        } else if(isDeleted) {
355	            DLogTagInfo(kBLEKeyTag, @"已删除钥匙，不包含证书钥匙，断开蓝牙");
356	            [XPBLEHandlerManager disconnectIsForce:true];
357	            weakSelf.isDeleteSuccess = YES;
358	            [weakSelf.deleteTimer invalidate];
359	            weakSelf.deleteTimer = nil;
360	            
361	            xp_async_execute_in_main_thread(^{
362	                [weakSelf.navigationController popViewControllerAnimated:YES];
363	                [XPToast showMessage:@"已删除"];
364	                [XPStatisticsMgr sendEvent:XP_DELETE_BLE_KEY_SUCCESS module:XP_DELETE_BLE_KEY_RESULT_MODULE];
365	            });
366	        }
367	    } repeats:YES];
368	}
