370	- (void)deleteCertKeyWithCertKeyCardNo:(NSString *)cardNo {
371	    if(![NetworkMonitorManager sharedManager].isReachable){
372	        [XPToast showMessage:BadNetworkTips];
373	        [self goToFailViewWithTips:BadNetworkTips];
374	    } else {
375	        @weakify(self);
376	        [[XPAPIRequestManager.sharedManager unbindCertKeyWithCardNumber:cardNo withVin:CTMediator.vin] subscribeNext:^(Response * _Nullable x) {
377	            @strongify(self);
378	            if(x.isSuccess) {
379	                DLogTagInfo(kBLEKeyTag, @"解绑证书钥匙成功，开始删除本地证书钥匙并断开蓝牙");
380	                if([XPBLEKeyManager.instance deleteCertKeyWithVin:self.vin]) {
381	                    [XPBLEHandlerManager disconnectIsForce:true];
382	                    self.isDeleteSuccess = YES;
383	                    [self.deleteTimer invalidate];
384	                    self.deleteTimer = nil;
385	                    
386	                    xp_async_execute_in_main_thread(^{
387	                        [[NSNotificationCenter defaultCenter] postNotificationName:XPDeletingBleKeyNotification object:nil];
388	                        [self.navigationController popViewControllerAnimated:YES];
389	                        [XPToast showMessage:@"已删除"];
390	                        [XPStatisticsMgr sendEvent:XP_DELETE_BLE_KEY_SUCCESS module:XP_DELETE_BLE_KEY_RESULT_MODULE];
391	                    });
392	                } else {
393	                    DLogTagError(kBLEKeyTag, @"删除本地证书钥匙失败");
394	                    [self goToFailViewWithTips:@"抱歉发生了错误，请稍后重试"];
395	                }
396	            } else {
397	                DLogTagInfo(kBLEKeyTag, @"解绑证书钥匙失败:%@", x.error);
398	                [self goToFailViewWithTips:@"抱歉发生了错误，请稍后重试"];
399	            }
400	        } error:^(NSError * _Nullable error) {
401	            @strongify(self);
402	            DLogTagInfo(kBLEKeyTag, @"解绑证书钥匙失败:%@", error);
403	            [self goToFailViewWithTips:@"抱歉发生了错误，请稍后重试"];
404	        }];
405	    }
406	}
