408	- (void)checkIsDeleteSuccessAfterDoorIsLocked {
409	    __weak typeof(self) weakSelf = self;
410	    self.step2View.secondsLabel.text = [NSString stringWithFormat:@"%ld", (long)self.seconds];
411	    self.step2View.sLabel.text = @"s";
412	    self.step3View.secondsLabel.text = [NSString stringWithFormat:@"%ld", (long)self.seconds];
413	    self.step3View.sLabel.text = @"s";
414	    self.secondsTimer = [NSTimer bk_scheduledTimerWithTimeInterval:1 block:^(NSTimer *timer) {
415	        weakSelf.seconds--;
416	        weakSelf.step2View.secondsLabel.text = [NSString stringWithFormat:@"%ld", (long)weakSelf.seconds];
417	        weakSelf.step3View.secondsLabel.text = [NSString stringWithFormat:@"%ld", (long)weakSelf.seconds];
418	        if(weakSelf.seconds <= 0) {
419	            [weakSelf.secondsTimer invalidate];
420	            weakSelf.secondsTimer = nil;
421	            if(!weakSelf.isDeleteSuccess) {
422	                if(weakSelf.card.cardType == XPBLEKeyCardType_BLEKey) {
423	                    if([weakSelf.card deleteCard]) {
424	                        DLogTagInfo(kBLEKeyTag, @"删除钥匙%ld秒已到，未成功，删除本地安全钥匙，删除成功", (long)kDeleteDuration);
425	                        XPDigitalKeyManageViewModel* viewModel = [XPBLEKeyManager.instance viewModelWithVin:weakSelf.vin];
426	                        if(weakSelf.card.cardType == XPBLEKeyCardType_BLEKey && viewModel.certKeyCard) {
427	                            DLogTagInfo(kBLEKeyTag, @"有证书钥匙，跳到删除失败页");
428	                            [weakSelf goToFailViewWithTips:@"抱歉发生了错误，请稍后重试"];
429	                        } else {
430	                            DLogTagInfo(kBLEKeyTag, @"已删除钥匙，不包含证书钥匙");
431	                            xp_async_execute_in_main_thread(^{
432	                                [weakSelf.navigationController popViewControllerAnimated:YES];
433	                                [XPToast showMessage:@"已删除"];
434	                                [XPStatisticsMgr sendEvent:XP_DELETE_BLE_KEY_SUCCESS module:XP_DELETE_BLE_KEY_RESULT_MODULE];
435	                            });
436	                        }
437	                    } else {
438	                        DLogTagInfo(kBLEKeyTag, @"删除本地安全钥匙失败");
439	                        [weakSelf goToFailViewWithTips:@"抱歉发生了错误，请稍后重试"];
440	                    }
441	                } else {
442	                    DLogTagInfo(kBLEKeyTag, @"删除钥匙%ld秒已到，未成功，跳转到失败页面", (long)kDeleteDuration);
443	                    [weakSelf goToFailViewWithTips:@"抱歉发生了错误，请稍后重试"];
444	                }
445	            }
446	        }
447	    } repeats:YES];
448	}
