126	    [[XPVehicleSDK.shared.vehicleManager currentVehicle]
127	     sendCommand:XPVehicleCommandLock success:^{
128	        self.step1View.lockButton.enabled = YES;
129	        DLogTagInfo(kBLEKeyTag, @"锁车成功，刷新整车状态，并跳转到删除授权第二步");
130	        [[XPVehicleSDK.shared.vehicleManager currentVehicle]
131	                   sendCommand:XPVehicleCommandForceUploadCarInfo extParams:nil success:^{
132	                [XPToast dismissLoadingMessage];
133	                [self.step1View removeFromSuperview];
134	                [self goToStep2];
135	        } failed:^(XPVehicleError * _Nonnull error) {
136	            [XPToast dismissLoadingMessage];
137	            [self.step1View removeFromSuperview];
138	            [self goToStep2];
139	        }];
140	    } failed:^(XPVehicleError * error) {
141	        self.step1View.lockButton.enabled = YES;
142	        [XPToast dismissLoadingMessage];
143	        [XPToast removePreviewToastOnView];
144	        dispatch_async(dispatch_get_main_queue(), ^{
145	            NSString *title = @"锁车失败，请检查";
146	            NSString *message = @"1. 请确保主驾无人\n2. 车门及前后盖已关闭\n3. 挡位置于P挡\n4. 车辆网络良好";
147	            if(error.channel == XPVehicleChannelTCP && error.code == 12){
148	                title = error.msg;
149	                message = nil;
150	            }
151	            [QMUIAlertController showAlertWithTitle:title
152	                                            message:message
153	                                   leftButtionTitle:nil
154	                                     leftButtonType:QMUIAlertActionStyleCancel
155	                                         leftAction:nil
156	                                   rightButtonTitle:@"确认"
157	                                    rightButtonType:QMUIAlertActionStyleDefault
158	                                        rightAction:nil];
159	        });
160	        DLogTagInfo(kBLEKeyTag, @"锁车失败:%@", error.msg);
161	    }];
162	}
