173	- (void)goToStep2 {
174	    [self.view addSubview:self.step2View];
175	    [self.step2View mas_makeConstraints:^(MASConstraintMaker *make) {
176	        make.edges.equalTo(self.view);
177	    }];
178	    
179	    __weak typeof(self) weakSelf = self;
180	    self.deleteTimer = [NSTimer bk_scheduledTimerWithTimeInterval:3 block:^(NSTimer *timer) {
181	        [[weakSelf.checkCarStatusViewModel.checkVehicleStatusCommand execute:@{@"vin":weakSelf.vin?:@"",
182	                                                             @"operType":@(XPKeyCardOperationTypeDelete),
183	                                                             @"cardType":@(XPBLEKeyCardType_BLEKey),
184	                                                             @"remoteLockResult":@(CTMediator.carState.doorInfo.driver_door_lock_st? 1:2)
185	        }] subscribeNext:^(id  _Nullable x) {
186	            
187	        } error:^(NSError * _Nullable error) {
188	            DLogTagInfo(kBLEKeyTag, @"检车车况失败%@", error);
189	        } completed:^{
190	            if(CTMediator.carState.powerInfo.car_igon_state != 0) {
191	                DLogTagInfo(kBLEKeyTag, @"检车车况正常，但车辆处于上电状态，跳转到失败界面");
192	                [weakSelf.deleteTimer invalidate];
193	                weakSelf.deleteTimer = nil;
194	                [weakSelf.step2View removeFromSuperview];
195	
196	                [weakSelf goToFailPageWithTips:@"车辆已上电，请确认锁车下电后重试"];
197	            } else {
198	                DLogTagInfo(kBLEKeyTag, @"检车车况正常，跳转到解除车辆授权第三步");
199	                [weakSelf.deleteTimer invalidate];
200	                weakSelf.deleteTimer = nil;
201	                [weakSelf.step2View removeFromSuperview];
202	                
203	                [weakSelf goToStep3];
204	            }
205	        }];
206	    } repeats:YES];
207	}
