217	    [self.step3View.animationView setCompatibleAnimation:[[CompatibleAnimation alloc] initWithName:@"createBleKeyStep2" subdirectory:nil bundle:NSBundle.mainBundle]];
218	    self.step3View.animationView.loopAnimationCount = -1;
219	    [self.step3View.animationView play];
