225	- (void)deleteWarranty {
226	    if (self.isAuthorizedPerson) {
227	        @weakify(self);
228	        [[CTMediator deleteGrantedVehicleWithVin:self.vin] subscribeNext:^(id  _Nullable x) {
229	        } error:^(NSError * _Nullable error) {
230	            DLogTagInfo(kBLEKeyTag, @"删除授权失败:%@", error);
231	        } completed:^{
232	            @strongify(self);
233	            [XPToast showMessage:@"已解绑车辆"];
234	            [self refreshAuthList];
