244	        @weakify(self);
245	        [[self.cancelWarrantyViewModel.requestCancelDriverCommand execute:nil] subscribeNext:^(id  _Nullable x) {
246	        } error:^(NSError * _Nullable error) {
247	            DLogTagInfo(kBLEKeyTag, @"删除授权失败:%@", error);
248	        } completed:^{
249	            @strongify(self);
250	            [XPToast showMessage:@"已解除授权"];
251	            DLogTagInfo(kBLEKeyTag, @"解除授权成功");
