264	    @weakify(self)
265	    [XPVehicleSDK.shared.vehicleManager requestVehicleInfo: ^{
266	        @strongify(self)
267	        DLogTagInfo(kBLEKeyTag, @"车辆授权，刷新车辆数据成功");
