269	            DLogTagInfo(kBLEKeyTag, @"车辆授权，刷新个人信息成功");
270	        }];
271	        [NSNotificationCenter.defaultCenter postNotificationName:XPCarPermissionNotificaiton object:nil];
272	    } failed :^(XPVehicleError * error) {
