284	- (void)checkIsDeleteSuccessAfterDoorIsLocked {
285	    self.step2View.secondsLabel.text = [NSString stringWithFormat:@"%ld", (long)self.seconds];
286	    self.step2View.sLabel.text = @"s";
287	    self.step3View.secondsLabel.text = [NSString stringWithFormat:@"%ld", (long)self.seconds];
288	    self.step3View.sLabel.text = @"s";
