328	        if([error.userInfo[@"code"] integerValue] == MQTTResponseCodeSomeoneIsControlingCar){
329	            title = error.userInfo[NSLocalizedFailureReasonErrorKey];
330	            message = nil;
331	        }
332	        [QMUIAlertController showAlertWithTitle:title
333	                                        message:message
334	                               leftButtionTitle:nil
335	                                 leftButtonType:QMUIAlertActionStyleCancel
336	                                     leftAction:nil
337	                               rightButtonTitle:@"确认"
338	                                rightButtonType:QMUIAlertActionStyleDefault
339	                                    rightAction:nil];
