55	    
56	    [self.view addSubview:self.step1View];
57	    [self.step1View mas_makeConstraints:^(MASConstraintMaker *make) {
58	        make.edges.equalTo(self.view);
59	    }];
60	    @weakify(self)
61	    [[self.step1View.lockButton rac_signalForControlEvents:UIControlEventTouchUpInside] subscribeNext:^(__kindof UIControl * _Nullable x) {
62	        @strongify(self)
63	        if([self judgeCanLock]) {
64	            self.step1View.lockButton.enabled = NO;
65	            [XPToast showLoadingMessage:@"锁车中..." hasMask:YES];
66	            [[self.carStateBusinessOperator.controlDoorCommand execute:@{@"isLock":@(YES),
