68	            }].deliverOnMainThread subscribeError:^(NSError * _Nullable error) {
69	                self.step1View.lockButton.enabled = YES;
70	                [XPToast dismissLoadingMessage];
71	                [XPToast removePreviewToastOnView];
72	                [self showFailToLockAlertWithError:error];
73	                DLogTagInfo(kBLEKeyTag, @"锁车失败:%@", error.userInfo[NSLocalizedFailureReasonErrorKey]);
74	            } completed:^{
75	                self.step1View.lockButton.enabled = YES;
76	                DLogTagInfo(kBLEKeyTag, @"锁车成功，刷新整车状态，并跳转到创建钥匙第二步");
77	                [[XPVehicleSDK.shared.vehicleManager currentVehicle]
78	                       sendCommand:XPVehicleCommandForceUploadCarInfo extParams:nil success:^{
79	                } failed:^(XPVehicleError * _Nonnull error) {
80	                }];
81	                [XPToast dismissLoadingMessage];
82	                [self.step1View removeFromSuperview];
83	                [self goToStep2];
84	            }];
