87	
88	    [[self.step1View.backButton rac_signalForControlEvents:UIControlEventTouchUpInside] subscribeNext:^(__kindof UIControl * _Nullable x) {
89	        @strongify(self)
90	        [self.navigationController popViewControllerAnimated:YES];
91	    }];
