94	- (void)goToStep2 {
95	    [self.view addSubview:self.step2View];
96	    [self.step2View mas_makeConstraints:^(MASConstraintMaker *make) {
97	        make.edges.equalTo(self.view);
98	    }];
99	    
100	    __weak typeof(self) weakSelf = self;
101	    weakSelf.createKeyTimer = [NSTimer bk_scheduledTimerWithTimeInterval:3 block:^(NSTimer *timer) {
102	        [[weakSelf.viewModel.checkVehicleStatusCommand execute:@{@"vin":weakSelf.vin?:@"",
103	                                                             @"operType":@(XPKeyCardOperationTypeAdd),
104	                                                             @"cardType":@(XPBLEKeyCardType_NFCWatchKey),
105	                                                             @"remoteLockResult":@(CTMediator.carState.doorInfo.driver_door_lock_st? 1:2)
106	        }] subscribeNext:^(id  _Nullable x) {
107	            
108	        } error:^(NSError * _Nullable error) {
109	            DLogTagInfo(kBLEKeyTag, @"检车车况失败%@", error);
110	        } completed:^{
111	            if(CTMediator.carState.powerInfo.car_igon_state != 0) {
112	                DLogTagInfo(kBLEKeyTag, @"检车车况正常，但车辆处于上电状态，跳转到失败界面");
113	                [weakSelf.createKeyTimer invalidate];
114	                weakSelf.createKeyTimer = nil;
115	                [weakSelf.step2View removeFromSuperview];
116	
117	                [weakSelf goToFailViewWithTips:@"车辆已上电，请确认锁车下电后重试"];
118	            } else {
119	                DLogTagInfo(kBLEKeyTag, @"车辆处于下电状态，检车车况正常，跳转到创建钥匙第三步");
120	                [weakSelf.createKeyTimer invalidate];
121	                weakSelf.createKeyTimer = nil;
122	                [weakSelf.step2View removeFromSuperview];
123	
124	                [weakSelf goToStep3];
125	            }
126	        }];
127	    } repeats:YES];
128	}
