130	- (void)goToStep3 {
131	    if(!CTMediator.defaultCarInfo.isSupportNFCKey) {
132	        DLogTagInfo(kBLEKeyTag, @"该车不支持NFC钥匙");
133	    }
134	    
135	    [self.view addSubview:self.step3View];
136	    [self.step3View mas_makeConstraints:^(MASConstraintMaker *make) {
137	        make.edges.equalTo(self.view);
138	    }];
139	    self.step3View.titleLabel.text = @"正在创建手表NFC钥匙";
140	    self.step3View.bleImageView.image = [UIImage imageNamed:@"ic_nfcwatch"];
141	    [self.step3View.animationView stop];
142	    [self.step3View.animationView setCompatibleAnimation:[[CompatibleAnimation alloc] initWithName:@"createBleKeyStep2" subdirectory:nil bundle:NSBundle.mainBundle]];
143	    self.step3View.animationView.loopAnimationCount = -1;
144	    [self.step3View.animationView play];
145	    
146	    [self.step3View.animationView addSubview:self.waitingLabel];
147	    [self.waitingLabel mas_makeConstraints:^(MASConstraintMaker *make) {
148	        make.centerX.equalTo(self.step3View.animationView.mas_centerX);
149	        make.bottom.equalTo(self.step3View.animationView.mas_bottom).offset(-155*AdaptiveRatio);
150	    }];
151	    
152	    [self jumpToHuamiApp];
153	    
154	    //5秒刷新一次
155	    __weak typeof(self) weakSelf = self;
156	    XPDigitalKeyManageViewModel* viewModel = [XPBLEKeyManager.instance viewModelWithVin:self.vin];
157	    weakSelf.createKeyTimer = [NSTimer bk_scheduledTimerWithTimeInterval:5 block:^(NSTimer *timer) {
158	        [weakSelf refreshKeyList];
159	        BOOL exist = [XPVehicleSDK.shared.vehicleManager.currentVehicle.digitalKeyManager digitalKeyWithKeyCardType:XPKeyCardTypeNFC_WATCH] != nil;
160	        if(exist) {
161	            //已激活
162	            DLogTagInfo(kBLEKeyTag, @"华米NFC钥匙已激活");
163	            weakSelf.isCreateSuccess = YES;
164	            [weakSelf.createKeyTimer invalidate];
165	            weakSelf.createKeyTimer = nil;
166	            
167	            [weakSelf.step3View removeFromSuperview];
168	            weakSelf.createSuccessView.type = KeyCreateSuccessViewTypeWatch;
169	            [weakSelf.view addSubview:weakSelf.createSuccessView];
170	            [weakSelf.createSuccessView mas_makeConstraints:^(MASConstraintMaker *make) {
171	                make.edges.equalTo(weakSelf.view);
172	            }];
173	            [[weakSelf.createSuccessView.experienceButton rac_signalForControlEvents:UIControlEventTouchUpInside] subscribeNext:^(__kindof UIControl * _Nullable x) {
174	                [weakSelf.navigationController popViewControllerAnimated:YES];
175	            }];
176	        }
177	    } repeats:YES];
178	}
