180	- (void)refreshKeyList{
181	    [XPVehicleSDK.shared.vehicleManager.currentVehicle.digitalKeyManager refreshRemoteKeyList];
182	}
183	
184	- (void)jumpToHuamiApp {
185	    NSString* url = @"amazfit://nfccard/create_car_card?";
186	    NSDictionary* params = @{@"vin":CTMediator.vin,
187	                               @"opType":@(1),
188	                               @"effectiveTime":@((uint64_t)ceil(time(NULL)/60.0)),
189	                               @"validTime":@(0)};
190	    @weakify(self);
191	    if(self.isNeedCreateBigCard) {
192	        [[[XPBLEKeyManager.instance.generateTokenCommand execute:nil] zipWith:[XPBLEKeyManager.instance.generateTokenForHuamiCommand execute:params]]
193	           subscribeNext:^(RACTwoTuple* _Nullable datas) {
194	            @strongify(self);
195	            DLogTagInfo(kBLEKeyTag, @"datas = %@",datas);
196	            RACTupleUnpack(NSDictionary* bigDcitionary,NSDictionary* smallDictionary) = datas;
197	            if(bigDcitionary[@"token"]) {
198	                NSString* parms = [NSString stringWithFormat:@"token=%@&keyToken=%@&action=bigCard",bigDcitionary[@"token"],smallDictionary[@"token"]];
199	                NSString* URL = [url stringByAppendingString:parms];
200	                DLogTagInfo(kBLEKeyTag, @"正在打开华米手表APP,url=%@",URL);
201	                [XPRouterUtil openURL:URL];
202	            }
203	          } error:^(NSError * _Nullable error) {
204	              @strongify(self);
205	              DLogTagError(kBLEKeyTag, @"error:%@",error);
206	              if(error.code == 11092112) {
207	                  [self dealWithWhenKeyIsExistedThenCreate:YES];
208	              }
209	          }];
210	    } else {
211	        [[XPBLEKeyManager.instance.generateTokenForHuamiCommand execute:@{@"uid":@(CTMediator.uid),@"vin":CTMediator.vin}] subscribeNext:^(NSDictionary* _Nullable smallDictionary) {
212	            @strongify(self);
213	            DLogTagInfo(kBLEKeyTag, @"data = %@",smallDictionary);
214	            if(smallDictionary[@"token"]) {
215	                 NSMutableDictionary* keyTokens = [NSMutableDictionary dictionary];
216	                 [keyTokens setObject:smallDictionary[@"token"] forKey:@"keyToken"];
217	                 [keyTokens setObject:@"" forKey:@"token"];
218	                 [keyTokens setObject:@"keyCard" forKey:@"action"];
219	                 NSMutableArray* params = [NSMutableArray arrayWithCapacity:2];
220	                 for (NSString* key in keyTokens.allKeys) {
221	                     [params addObject:[NSString stringWithFormat:@"%@=%@",key,[keyTokens objectForKey:key]]];
222	                 }
223	                NSString* URL = [url stringByAppendingString:[params componentsJoinedByString:@"&"]];
224	                DLogTagInfo(kBLEKeyTag, @"正在打开华米手表APP,url=%@",URL);
225	                [XPRouterUtil openURL:URL];
226	            } else {
227	                DLogTagInfo(kBLEKeyTag, @"token为空");
228	            }
229	        } error:^(NSError * _Nullable error) {
230	            DLogTagError(kBLEKeyTag, @"error:%@",error);
231	            @strongify(self);
232	            if(error.code == 11092112) {
233	                [self dealWithWhenKeyIsExistedThenCreate:YES];
234	            }
235	        } completed:^{
236	        }];
237	    }
238	}
239	
240	- (void)dealWithWhenKeyIsExistedThenCreate:(BOOL)create {
241	    DLogTagInfo(kBLEKeyTag, @"服务端已存在手表钥匙，需要删除");
242	    BOOL isSelfKey = NO;
243	    NSString *cardNo = nil;
244	    XPBLEKeyCard *watchCard = [XPBLEKeyCard yy_modelWithDictionary:[[XPVehicleSDK.shared.vehicleManager.currentVehicle.digitalKeyManager digitalKeyWithKeyCardType:XPKeyCardTypeNFC_WATCH].bleKeyCard toDict]];
245	    cardNo = watchCard.cardNo;
246	    isSelfKey = watchCard != nil && (watchCard.status == XPBLEKeyCardStatusActivated || watchCard.status == XPBLEKeyCardStatusToBeActivated);
247	    if(isSelfKey) {
248	        DLogTagInfo(kBLEKeyTag, @"服务端已存在手表钥匙，而且钥匙是自己的(激活中或者待激活)，则先删除自己的");
249	        [self deleteKeyWithCardNumber:cardNo thenCreate:create];
250	    } else {
251	        DLogTagInfo(kBLEKeyTag, @"服务端已存在手表钥匙，而且钥匙是别人的，不能删除，直接跳到失败页面");
252	        [self goToFailViewWithTips:@"请重新再试"];
253	    }
254	}
255	
256	- (void)deleteKeyWithCardNumber:(NSString *)cardNumnber thenCreate:(BOOL)create {
257	    @weakify(self);
258	    [[[XPBLEKeyManager.instance.destoryBLEKeyCommand execute:cardNumnber] takeUntil:self.rac_willDeallocSignal].deliverOnMainThread subscribeError:^(NSError * _Nullable error) {
259	        @strongify(self)
260	        DLogTagError(kBLEKeyTag, @"%@",error);
261	
262	        if (ERR_IFAA_DEVICE_NOT_REGISTERED == error.code) {
263	            [[[XPBLEKeyManager.instance.requestDestroyCardInThisDeviceCommand execute:nil] takeUntil:self.rac_willDeallocSignal].deliverOnMainThread subscribeError:^(NSError * _Nullable error) {
264	                DLogTagInfo(kBLEKeyTag, @"注销失败%@", error);
265	            } completed:^{
266	                DLogTagInfo(kBLEKeyTag, @"申请注销成功");
267	                @strongify(self)
268	                [self refreshKeyList];
269	                if(create) {
270	                    DLogTagInfo(kBLEKeyTag, @"检查钥匙的删除状态");
271	                    [self checkCardIsDeletedAndCreate];
272	                }
273	            }];
274	        } else {
275	            DLogTagInfo(kBLEKeyTag, @"注销失败%@", error.localizedFailureReason);
276	        }
277	    } completed:^{
278	        DLogTagInfo(kBLEKeyTag, @"申请注销成功");
279	        @strongify(self)
280	        if(create) {
281	            DLogTagInfo(kBLEKeyTag, @"检查钥匙的删除状态");
282	            [self checkCardIsDeletedAndCreate];
283	        }
284	    }];
285	}
286	
287	- (void)checkCardIsDeletedAndCreate {
288	    __weak typeof(self) weakSelf = self;
289	    self.createKeyTimer = [NSTimer bk_scheduledTimerWithTimeInterval:3 block:^(NSTimer *timer) {
290	        XPDigitalKeyManageViewModel *viewModel = [XPBLEKeyManager.instance viewModelWithVin:weakSelf.vin];
291	        if(![viewModel myWatchNFCCardIsExisted]) {
292	            DLogTagInfo(kBLEKeyTag, @"手表钥匙删除成功, 继续走创建流程");
293	            [weakSelf.createKeyTimer invalidate];
294	            weakSelf.createKeyTimer = nil;
295	            [weakSelf jumpToHuamiApp];
296	        } else {
297	            DLogTagInfo(kBLEKeyTag, @"手表钥匙还没删除,跳到失败页面");
298	            [weakSelf.createKeyTimer invalidate];
299	            weakSelf.createKeyTimer = nil;
300	            [weakSelf goToFailViewWithTips:@"请重新再试"];
301	        }
302	    } repeats:YES];
303	}
304	
